parameters.jsCode:
// Parse payment event from portal webhook handler
const body = $input.first().json.body || $input.first().json;

const event = body.event || 'unknown';
const applicationId = body.application_id || '';
const userId = body.user_id || '';
const firstName = body.first_name || '';
const lastName = body.last_name || '';
const email = body.email || '';
const phone = body.phone || '';
const programId = body.program_id || '';
const tempPassword = body.temp_password || '';
const loginUrl = body.login_url || 'https://portal.coineducation.com/login';
const paymentIntentId = body.payment_intent_id || '';
const failureMessage = body.failure_message || '';

return [{
  json: {
    event,
    applicationId,
    userId,
    firstName,
    lastName,
    email,
    phone,
    programId,
    tempPassword,
    loginUrl,
    paymentIntentId,
    failureMessage
  }
}];

